/// Resolve a slug to its self-contained widget HTML bundle.
pub fn html_for_slug(slug: &str) -> Option<&'static str> {
    APP_BUNDLES
        .iter()
        .find(|bundle| bundle.slug == slug)
        .map(|bundle| bundle.html)
}
